GamePacketHandler = {}

function GamePacketHandler:init()
    C2SDoWorkout:registerCallBack(self.onDoWorkout)
    C2STeleportToArea:registerCallBack(self.TeleportToArea)
    C2SDoQuanJi:registerCallBack(self.onDoQuanJi)
    C2SDoJiaoCai:registerCallBack(self.onDoJiaoCai)
    C2SChangeHoldItemActor:registerCallBack(self.onChangeHoldItemActor)
    C2SPlaySkill:registerCallBack(self.onPlaySkill)
    C2STeleportAreaEvent:registerCallBack(self.onTeleportAreaEvent)
    C2SBuyPayItem:registerCallBack(self.onBuyPayItem)
    C2STeleAutoWorkout:registerCallBack(self.onTeleAutoWorkout)
    C2SConcealPower:registerCallBack(self.onConcealPower)
    C2SBuySkin:registerCallBack(self.onBuySkin)
    C2SEquipSkin:registerCallBack(self.onEquipSkin)
    C2SSelectSkin:registerCallBack(self.onSelectSkin)
    C2STeleAutoWorkoutBack:registerCallBack(self.onAutoWorkoutBack)
    C2SDoReport:registerCallBack(self.onDoReport)
    C2SAddInvincibleState:registerCallBack(self.onAddInvincibleState)
    C2SGuideClickNext:registerCallBack(self.onGuideClickNext)
    C2SGoToChampionshipClick:registerCallBack(self.onGoToChampionshipClick)
end

function GamePacketHandler.onDoWorkout(userId, data)
    --HostApi.log("GamePacketHandler.onDoWorkout")

    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end

    local builder = DataBuilder.new():fromData(data)

    --local fitnessEquipId = builder:getNumberParam("fitnessEquipId")

    player:doWorkout()
end

function GamePacketHandler.TeleportToArea(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end

    local builder = DataBuilder.new():fromData(data)
    local Area = builder:getParam("Area")
    player:teleportToArea(Area)
    GamePacketSender:sendAutoWorkoutBack(player.rakssid, false)
end

function GamePacketHandler.onDoQuanJi(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end

    player:doQuanJi()
end

function GamePacketHandler.onDoJiaoCai(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
