function GamePacketHandler.onChangeHoldItemActor(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end

    local builder = DataBuilder.new():fromData(data)
    local itemId = builder:getNumberParam("ItemId")
    local selectMode = builder:getNumberParam("selectMode")
    player.property.selectMode = selectMode
    player.property:changeHoldItemActor(itemId)
    LogUtil.log(string.format("GamePacketHandler.onChangeHoldItemActor %d %d", itemId, selectMode))
end

function GamePacketHandler.onPlaySkill(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end

    local builder = DataBuilder.new():fromData(data)
    local skillId = builder:getNumberParam("skillId")
    if skillId == -1 then
        player:doGrab()
    else
        player:playSkill(skillId)
    end
end

function GamePacketHandler.onTeleportAreaEvent(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end

    local builder = DataBuilder.new():fromData(data)
    local eventId = builder:getNumberParam("eventId")
    GamePacketSender:sendAutoWorkoutBack(player.rakssid, false)
    AreaEventManager:doTeleportArea(player, eventId)
    ReportUtil.reportTeleportAreaEvent(player)
end

