function GamePacketHandler.onSelectSkin(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end

    local builder = DataBuilder.new():fromData(data)
    local index = builder:getNumberParam("index")
    if index == Define.SelectSkinType.Default then
        PayStore:onEquipSkin(player, -1)
    else
        PayStore:onEquipSkin(player, SkinConfig:getDefaultSkin(player))
    end

    ReportUtil.reportSelectSkin(player, index)

    player.property.showSelectSkinDlg = false
end

function GamePacketHandler.onDoReport(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end
    local builder = DataBuilder.new():fromData(data)
    ReportUtil.onDoReport(player, builder)
end

function GamePacketHandler.onAddInvincibleState(userId, data)

    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end
    local builder = DataBuilder.new():fromData(data)
    local time = builder:getNumberParam("Time")
    if player.curArea ~= Define.Area.ShopArea and player.curArea ~= Define.Area.AutoArea then
        player.property:addInvincibleState(time, false)
    end

    --ReportUtil.onDoReport(player, builder)

end

function GamePacketHandler.onGuideClickNext(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end

    local builder = DataBuilder.new():fromData(data)
    local index = builder:getNumberParam("index")

    player:changeNewGuiProgress(index)
end

function GamePacketHandler.onGoToChampionshipClick(userId)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end

    if player:isAdvancing() 
        or player.property.advancedLevel < GameConfig.btnChampionShipEnableLevel
        or player.property.muscleMass < GameConfig.btnChampionShipEnableMuscle then
        
        return
    end

    LogUtil.log("C2SGoToChampionshipClick " .. tostring(userId) .. " " .. player.property.advancedLevel .. " " .. GameConfig.btnChampionShipEnableLevel
            .. " " .. GameConfig.btnChampionShipEnableMuscle)

    JumpGameManager:addPlayer(player, "g1060")
end

return GamePacketHandler